from dataclasses import dataclass, field
from typing import Any


@dataclass
class BeliefState:
    """Tracks the agent's best estimate of hidden state variables."""

    _beliefs: dict[str, Any] = field(default_factory=dict)
    confidences: dict[str, float] = field(default_factory=dict)

    def update(self, key: str, value: Any, confidence: float = 1.0) -> None:
        """Record a new belief with an associated confidence score."""
        self._beliefs[key] = value
        self.confidences[key] = max(0.0, min(1.0, confidence))

    def get(self, key: str, default: Any = None) -> Any:
        return self._beliefs.get(key, default)

    def decay(self, factor: float) -> None:
        """Reduce confidence in all beliefs — information grows stale."""
        for k in self.confidences:
            self.confidences[k] *= factor

    def most_uncertain(self) -> str | None:
        """Return the key with the lowest confidence (most uncertain belief)."""
        if not self.confidences:
            return None
        return min(self.confidences, key=lambda k: self.confidences[k])


# --- Partial observation: robot cannot see around corners ---
bs = BeliefState()
bs.update("own_position", (3, 4), confidence=0.99)   # GPS — high confidence
bs.update("obstacle_ahead", False, confidence=0.70)  # sensor estimate
bs.update("target_location", (10, 2), confidence=0.50)  # last known, fading

print(bs.most_uncertain())          # "target_location"
bs.decay(0.9)                       # one time-step passes
print(bs.confidences["target_location"])  # 0.45

from typing import Callable


def observation_filter(
    full_state: dict,
    visible_keys: set[str],
) -> dict:
    """Simulate partial observability by masking state keys."""
    return {k: v for k, v in full_state.items() if k in visible_keys}


FULL_STATE = {
    "player_hp": 80,
    "player_position": (5, 3),
    "enemy_hp": 40,
    "enemy_position": (8, 3),
    "fog_of_war_cells": [(6, 3), (7, 3)],  # hidden
}

VISIBLE = {"player_hp", "player_position"}  # fog of war hides the rest

percept = observation_filter(FULL_STATE, VISIBLE)
print(percept)
# {"player_hp": 80, "player_position": (5, 3)}
# Enemy HP and position are hidden — agent must infer or remember

class HybridObservabilityAgent:
    """
    Uses full observation when available, falls back to belief state
    when sensors are occluded or unreliable.
    """

    def __init__(self):
        self.belief = BeliefState()

    def perceive(self, sensor_data: dict[str, Any]) -> None:
        """Integrate sensor readings; high confidence = near-full observation."""
        for key, (value, confidence) in sensor_data.items():
            self.belief.update(key, value, confidence)

    def act(self) -> str:
        """Choose strategy based on how observable the environment currently is."""
        avg_conf = (
            sum(self.belief.confidences.values()) /
            max(1, len(self.belief.confidences))
        )

        if avg_conf >= 0.9:        # effectively fully observable right now
            return "exploit"       # act greedily on known state
        elif avg_conf >= 0.5:
            return "plan"          # plan under uncertainty
        else:
            return "explore"       # gather more observations first

from dataclasses import dataclass
import math


@dataclass
class GaussianSensor:
    """
    Models a noisy continuous sensor: true value + Gaussian noise.
    Used to compute the likelihood P(observation | true_state).
    """

    std_dev: float = 1.0     # sensor noise level

    def likelihood(self, obs: float, true_value: float) -> float:
        """P(obs | true_value) under N(true_value, std_dev^2)."""
        diff = obs - true_value
        return math.exp(-0.5 * (diff / self.std_dev) ** 2) / (
            self.std_dev * math.sqrt(2 * math.pi)
        )

    def update_belief(
        self,
        prior: dict[float, float],
        obs: float,
    ) -> dict[float, float]:
        """Bayesian update over a discrete set of candidate states."""
        posterior = {}
        for state, prior_prob in prior.items():
            posterior[state] = self.likelihood(obs, state) * prior_prob
        total = sum(posterior.values())
        return {s: p / total for s, p in posterior.items()}


# Robot estimates room temperature; sensor has std_dev=2.0 degrees
sensor = GaussianSensor(std_dev=2.0)

# Prior: temperature equally likely to be 18, 20, or 22 degrees
prior = {18.0: 1/3, 20.0: 1/3, 22.0: 1/3}

# Sensor reads 21.5 degrees
posterior = sensor.update_belief(prior, obs=21.5)
for temp, prob in sorted(posterior.items()):
    print(f"  {temp:.0f}°C: {prob:.3f}")
# 18°C: 0.087  20°C: 0.413  22°C: 0.500  (belief shifts toward 22°)

from dataclasses import dataclass, field


@dataclass
class InformationGatheringAgent:
    """
    In a partially observable environment, the agent should sometimes
    take actions specifically to REDUCE uncertainty rather than to
    advance toward the goal.
    """

    belief: BeliefState = field(default_factory=BeliefState)
    steps_since_scan: int = 0
    SCAN_THRESHOLD: float = 0.65    # re-scan when avg confidence drops below this
    SCAN_INTERVAL: int = 5          # also scan every N steps regardless

    def perceive(self, sensor_data: dict) -> None:
        for key, (value, confidence) in sensor_data.items():
            self.belief.update(key, value, confidence)

    def _avg_confidence(self) -> float:
        if not self.belief.confidences:
            return 0.0
        return sum(self.belief.confidences.values()) / len(self.belief.confidences)

    def act(self) -> str:
        self.belief.decay(0.95)
        self.steps_since_scan += 1

        avg_conf = self._avg_confidence()

        # Proactively gather information when uncertainty is high
        if avg_conf < self.SCAN_THRESHOLD or self.steps_since_scan >= self.SCAN_INTERVAL:
            self.steps_since_scan = 0
            return "scan_environment"

        # Enough certainty to act toward goal
        target = self.belief.get("target_position")
        if target is not None:
            return f"move_toward {target}"

        return "scan_environment"  # no known goal — gather more info
